INSERT INTO pages (slug, title, type) VALUES ('creativite-sens-critique', 'Créativité & Sens Critique', 'competence');
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'header_title', 'h1', 'Créativité & Sens Critique', 'hero', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'header_breadcrumb', 'label', 'home / compétences', 'hero', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'definition_title', 'h2', 'DEFINITION', 'definition', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'definition_p1', 'paragraph', 'Selon moi, la créativité et le sens critique sont deux compétences liées en informatique. Elles sont essentielles car elles stimulent la conception d''application, d''architecture et les compétences de programmation.\n\nCe sont les capacités à inventer des solutions à des problèmes algorithmiques mais également à concevoir des architectures inspirées d''autres mais qui s''adaptent à l''environnement de développement d''une entreprise.', 'definition', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'definition_p2', 'paragraph', 'Etre en capacité de voir si une solution apportée est viable, maintenable et simple suppose un sens critique qui repose sur l''expérience du programmeur.', 'definition', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'definition_p3', 'paragraph', 'Ces deux compétences vont de paire car l''objectif d''un programmeur est de développer des solutions viables et c''est ce sens critique qui permet de cadrer la capacité à créer.', 'definition', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section1_number', 'number', '1', 'preuves', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section1_title', 'h2', 'éléments de preuves', 'preuves', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section1_p1', 'paragraph', 'Durant mon parcours d''étude en programmation, la créativité et le sens critique ont toujours été une paire de compétences que j''ai travaillées. Lors de projet d''applications, j''ai imaginé en groupe des applications qui répondent à un besoin ciblé, par exemple, en codant une application de location de bungalows pour les salariés d''une entreprise.\n\nDans le cadre de mon apprentissage continu, j''ai pensé à une application qui listerait les dernières sorties de films français par ville, ou encore à un générateur de voyages intelligent qui proposerait, pour chaque étape, des lieux touristiques et des logements à prix abordables.', 'preuves', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section1_p2', 'paragraph', 'Mes études en UX/UI design m''ont permis d''imaginer des applications répondant à un besoin utilisateur avant d''être un défi technique. J''ai également étudié et interrogé les utilisateurs sur l''utilité immédiate de l''application.\n\nLister les fonctionnalités d''une application et concevoir celles qui sont essentielles nécessitent beaucoup de créativité et un sens critique vis-à-vis de ce qui est imaginé.', 'preuves', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section1_p3', 'paragraph', 'créativité et esthétique visuelle\n\nBien que cela soit éloigné de mon cœur de métier, lors de mes expériences chez Coliback et MyCityStock, j''ai conçu des sites vitrines. Créer un site vitrine demande une veille graphique importante, une compréhension des tendances typographiques et colorimétriques dans divers domaines du web, et la création d''un site respectant ces codes.\n\nPour chaque site, je produis des maquettes sur Figma, d''abord des zonings présentant les différentes zones de contenu de chaque page, puis des wireframes plus subjectifs, et enfin des maquettes haute fidélité que je respecte lors de l''intégration du site en développement. J''ai également réalisé de nombreuses présentations commerciales pour expliquer les services développés aux clients, tout en respectant la charte graphique de Coliback.', 'preuves', 5);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section1_p4', 'paragraph', 'créativité et conception d''application\n\nChez Coliback, lors du développement de Coliback Premium, j''ai co-conçu avec mon responsable, David Dias, le comportement de l''application en tenant compte des contraintes techniques et des langages liés à Shopify, Node et GraphQL. Nous avions imaginé en amont les fonctionnalités essentielles du programme, puis j''ai eu beaucoup de liberté dans la conception de l''architecture sur le serveur NodeJS. J''ai dû faire preuve de créativité et de sens critique pour faire évoluer un programme tout en tenant compte de ces contraintes.\n\nLorsque j''ai développé un logiciel de génération de factures, GenFact, lié à l''environnement de comptabilité Sellsy, il a fallu inventer une approche concrète pour générer automatiquement des factures dans Sellsy via l''API.\n\nDans l''architecture logicielle, il faut également créer les tables de base de données, choisir les bonnes technologies pour celles-ci, réfléchir à la manière dont l''application se connectera à ces bases, et comment conserver un journal de log pour suivre le fonctionnement des logiciels.', 'preuves', 6);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section1_p5', 'paragraph', 'créativité et programmation\n\nLa nécessité de coder en clean code exige de faire preuve d''inventivité pour trouver des solutions originales et simples, tout en évitant la répétition de codes pour des problèmes algorithmiques. Concernant Coliback Premium, j''ai dû innover pour limiter les envois de requêtes GraphQL non nécessaires, qui auraient pu nuire aux performances de mon programme. Coder les bonnes interfaces, charger des payloads, imaginer le bus d''événements de l''application, tout cela nécessite de nombreux tests préalables avant d''atteindre le résultat escompté.', 'preuves', 7);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section2_number', 'number', '2', 'evolution', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section2_title', 'h2', 'évolution', 'evolution', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section2_p1', 'paragraph', 'La créativité et le sens critique sont deux compétences à nourrir tout le long d''une carrière en informatique, car elles suggèrent également une forme de curiosité pour le domaine.\n\nMes compétences en design et en développement ont été très utiles dans le cadre de création de nouvelles applications, j''aimerais poursuivre dans cette voie car je préfère cette approche de l''informatique où l''on crée un produit pour l''humain plus que le pendant plus technique comme l''infogérance ou l''aspect plus réseau où l''informaticien est plus proche de la machine et où les compétences techniques dépendent davantage des connaissances techniques.', 'evolution', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section3_number', 'number', '3', 'autocritique', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section3_title', 'h2', 'Autocritique', 'autocritique', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'section3_p1', 'paragraph', 'Cette liberté de création fait partie des raisons pour lesquelles j''aime ce métier de programmeur. Toutefois, j''ai pris conscience de l''importance d''être organisé et méthodique dans la réalisation des tâches à faire.\n\nNaturellement, j''aurais tendance à explorer de nouvelles pistes à réaliser et à trouver de nouvelles solutions si je ne m''imposais pas la réalisation de tâches pratiques et c''est sur ce point que je reste aussi le plus vigilant dans mon travail.', 'autocritique', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('creativite-sens-critique', 'projects_title', 'h2', 'projets', 'projets', 1);
